INSERT INTO questionnaires (id, type, title, description, version, active, created_at, updated_at) VALUES
('20000000-0000-0000-0000-000000000001','READINESS','NIS2-style cybersecurity readiness assessment','Readiness questionnaire based on NIS2 Article 21-style cybersecurity themes. Informational only, not legal advice.',1,true,now(),now()),
('20000000-0000-0000-0000-000000000002','SCOPING','NIS2 relevance scoping questionnaire','Informational estimate of whether the organization may need expert NIS2 scope review.',1,true,now(),now());
INSERT INTO questions (id, questionnaire_id, category, text, description, weight, recommended_evidence, recommended_action, sort_order) VALUES
('21000000-0000-0000-0000-000000000001','20000000-0000-0000-0000-000000000001','Governance','Do you maintain an information security policy?','Policy ownership, approval, communication, and periodic review.',5,'Approved policy and review record.','Create or update an information security policy and assign an owner.',10),
('21000000-0000-0000-0000-000000000002','20000000-0000-0000-0000-000000000001','Risk Management','Do you maintain a cybersecurity risk register?','Material cyber risks should have owners, treatment decisions, and dates.',5,'Risk register export.','Create a cyber risk register and review it regularly.',20),
('21000000-0000-0000-0000-000000000003','20000000-0000-0000-0000-000000000001','Asset Management','Do you maintain an inventory of critical IT assets?','Track laptops, servers, cloud services, applications, data stores, and owners.',5,'Asset inventory, CMDB screenshot, or device management report.','Create and maintain a critical asset inventory.',30),
('21000000-0000-0000-0000-000000000004','20000000-0000-0000-0000-000000000001','Access Control','Do privileged and remote-access accounts use MFA?','MFA is a high-value control for reducing account takeover risk.',5,'Identity provider MFA policy screenshot.','Enable MFA for privileged and remote access accounts.',40),
('21000000-0000-0000-0000-000000000005','20000000-0000-0000-0000-000000000001','Incident Handling','Do you maintain an incident response procedure?','Include detection, escalation, containment, communication, evidence preservation, and review.',5,'Incident response procedure and exercise notes.','Approve and test an incident response procedure.',50),
('21000000-0000-0000-0000-000000000006','20000000-0000-0000-0000-000000000001','Backup and Disaster Recovery','Do you test restoration of critical backups?','Backups only reduce risk when restoration has been verified.',5,'Backup restore test report.','Run restore tests for critical systems and record results.',60),
('21000000-0000-0000-0000-000000000007','20000000-0000-0000-0000-000000000001','Supply Chain Security','Do you review cybersecurity risk for important suppliers?','Supplier dependencies can create material operational risk.',5,'Supplier questionnaire or contract review notes.','Review critical suppliers and document security expectations.',70),
('21000000-0000-0000-0000-000000000008','20000000-0000-0000-0000-000000000001','Vulnerability Management','Do you track vulnerabilities through remediation?','Record severity, owners, deadlines, and closure evidence.',5,'Vulnerability tracker export.','Implement a vulnerability remediation tracker.',80),
('21000000-0000-0000-0000-000000000009','20000000-0000-0000-0000-000000000001','Security Training','Do employees complete cybersecurity awareness training?','Training should cover phishing, reporting, passwords, and data handling.',4,'Training attendance list.','Run awareness training and track attendance.',90),
('21000000-0000-0000-0000-000000000010','20000000-0000-0000-0000-000000000001','Logging and Monitoring','Do you log and review security-relevant events?','Important identity, endpoint, server, and application events should be available for review.',5,'Logging configuration export or alert process.','Enable logging and assign alert review responsibility.',100);
